sp_widget.client_script:
api.controller = function() {
  var c = this;
  c.data = c.data || {};
  c.submitting = false;
  c.form = {
    customer_name: '',
    customer_email: '',
    customer_phone: '',
    short_description: '',
    description: '',
    channel: '',
    priority: '3',
    urgency: '3'
  };

  c.submit = function() {
    c.data.errorMsg = '';
    c.data.successMsg = '';

    if (!c.form.customer_name || !c.form.customer_email || !c.form.short_description) {
      c.data.errorMsg = 'Please fill in all required fields.';
      return;
    }

    c.submitting = true;
    c.server.get({
      action: 'submit',
      customer_name: c.form.customer_name,
      customer_email: c.form.customer_email,
      customer_phone: c.form.customer_phone,
      short_description: c.form.short_description,
      description: c.form.description,
      channel: c.form.channel,
      priority: c.form.priority,
      urgency: c.form.urgency
    }).then(function(r) {
      c.data = r.data;
      if (r.data.success) {
        c.form = {};
      }
      c.submitting = false;
    }, function() {
      c.submitting = false;
      c.data.errorMsg = 'An error occurred. Please try again.';
    });
  };

  c.goToMyComplaints = function() {
    window.location.href = '?id=x_2091449_manage_0_my_complaints';
  };
};

sp_widget.css:
.sp-input {
  height: $input-height-base;
  border: 1px solid $border-tertiary;
  border-radius: $border-radius-base;
  padding: 0 12px;
  font-size: $font-size-base;
  color: $text-color;
  background: $background-primary;
  transition: border-color 0.15s, box-shadow 0.15s;
  width: 100%;
  &:focus {
    border-color: $brand-primary;
    box-shadow: 0 0 0 3px rgba($brand-primary, 0.15);
    outline: none;
  }
}
.sp-textarea {
  border-radius: $border-radius-base;
  border: 1px solid $border-tertiary;
  padding: 12px;
  font-size: $font-size-base;
  color: $text-color;
  background: $background-primary;
  resize: vertical;
  min-height: 100px;
  transition: border-color 0.15s;
  &:focus {
    border-color: $brand-primary;
    box-shadow: 0 0 0 3px rgba($brand-primary, 0.15);
    outline: none;
  }
}
.sp-btn-primary {
  height: 44px;
  padding: 0 20px;
  border-radius: $border-radius-base;
  font-size: $font-size-base;
  font-weight: 500;
  display: inline-flex;
  align-items: center;
  gap: 8px;
  transition: background 0.15s, box-shadow 0.15s;
  cursor: pointer;
  border: none;
  background: $brand-primary;
  color: $btn-primary-color;
  &:hover:not(:disabled) {
    background: $brand-primary-dark;
    box-shadow: 0 2px 8px rgba($brand-primary, 0.3);
    color: $btn-primary-color;
  }
  &:disabled {
    opacity: 0.55;
    cursor: not-allowed;
  }
}
.sp-btn-group {
  display: flex;
  gap: 8px;
  align-items: center;
  margin-top: 24px;
  flex-wrap: wrap;
}
.has-error .sp-input,
.has-error .sp-textarea {
  border-color: $brand-danger;
}
@keyframes sp-spin { to { transform: rotate(360deg); } }
.sp-spin { animation: sp-spin 0.8s linear infinite; }

sp_widget.script:
(function() {
  data.success = false;
  data.errorMsg = '';
  data.successMsg = '';
  data.caseNumber = '';
  data.channels = [];
  data.priorities = [];

  try {
    // Channel choices
    data.channels = [
      { value: 'call_center', label: 'Call Center' },
      { value: 'email', label: 'Email' },
      { value: 'website', label: 'Website' },
      { value: 'live_chat', label: 'Live Chat' },
      { value: 'chatbot', label: 'Chatbot' },
      { value: 'mobile_app', label: 'Mobile App' },
      { value: 'whatsapp', label: 'WhatsApp' },
      { value: 'instagram', label: 'Instagram' },
      { value: 'physical_store', label: 'Physical Store' },
      { value: 'marketplace', label: 'Marketplace' }
    ];

    // Priority choices
    data.priorities = [
      { value: '1', label: '1 - Critical' },
      { value: '2', label: '2 - High' },
      { value: '3', label: '3 - Moderate' },
      { value: '4', label: '4 - Low' }
    ];

    if (input && input.action === 'submit') {
      if (!input.short_description || !input.customer_name || !input.customer_email) {
        data.errorMsg = 'Please fill in all required fields.';
        return;
      }

      var gr = new GlideRecord('x_2091449_manage_0_consumer_case');
      gr.initialize();
      gr.setValue('short_description', input.short_description);
      gr.setValue('description', input.description || '');
      gr.setValue('customer_name', input.customer_name);
      gr.setValue('customer_email', input.customer_email);
      gr.setValue('customer_phone', input.customer_phone || '');
      gr.setValue('channel', input.channel || '');
      gr.setValue('priority', input.priority || '4');
      gr.setValue('urgency', input.urgency || '3');
      gr.setValue('state', '1');

      var sysId = gr.insert();
      if (sysId) {
        gr.get(sysId);
        data.success = true;
        data.caseNumber = gr.getValue('number') + '';
        data.successMsg = 'Your complaint has been submitted successfully. Case Number: ' + data.caseNumber;
      } else {
        data.errorMsg = 'Failed to create complaint. Please try again.';
      }
      return;
    }
  } catch (e) {
    gs.error('Create Complaint widget error: ' + e.message);
    data.errorMsg = 'An error occurred. Please try again.';
  }
})();
